import{_ as a,o as t,c as i,a3 as n}from"./chunks/framework.CjquFG0V.js";const v=JSON.parse(`{"title":"28. Family And Domestic Violence Leave","description":"","frontmatter":{"title":"28. Family And Domestic Violence Leave","eba":"Children's Services Award 2010","topics":["leave","family-violence-leave","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/leave/28-family-and-domestic-violence-leave.md","filePath":"ebas/childrens-services/leave/28-family-and-domestic-violence-leave.md"}`),o={name:"ebas/childrens-services/leave/28-family-and-domestic-violence-leave.md"};function r(s,e,l,d,c,m){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="_28-family-and-domestic-violence-leave" tabindex="-1">28. Family And Domestic Violence Leave <a class="header-anchor" href="#_28-family-and-domestic-violence-leave" aria-label="Permalink to &quot;28. Family And Domestic Violence Leave&quot;">​</a></h1><p>[28---Leave to deal with Family and Domestic Violence renamed and substituted by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/pr740264.htm" target="_blank" rel="noreferrer">PR740264</a>; 28---Unpaid family and domestic violence leave renamed and substituted by <a href="https://www.fwc.gov.au/documents/awardsandorders/pdf/pr750444.pdf" target="_blank" rel="noreferrer">PR750444</a> ppc 15Mar23]</p><p>Family and domestic violence leave is provided for in the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">NES</a>.</p><p>NOTE 1: Information provided to employers concerning an employee&#39;s experience of family and domestic violence is sensitive and if mishandled can have adverse consequences for the employee. Employers are subject to confidentiality requirements regarding the handling of this information under section 106C of the <a href="https://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a> and requirements as to what can be reported on payslips pursuant to regulations 3.47 and 3.48 of the <em>Fair Work Regulations 2009</em>.</p><p>NOTE 2: Depending upon the circumstances, evidence that would satisfy a reasonable person of the employee&#39;s need to take family and domestic violence leave may include a document issued by the police service, a court or family violence support service, or a statutory declaration.</p><p>Plain language terms: DV leave, FDV.</p>',6)])])}const f=a(o,[["render",r]]);export{v as __pageData,f as default};
